  useEffect(() => {
    const initLiff = async () => {
      try {
        // @ts-ignore
        const liff = window.liff;
        if (liff) {
          await liff.init({ liffId: '2007509057-QWw2WLrq' });
          if (liff.isLoggedIn()) {
            const profile = await liff.getProfile();
            setLineUserId(profile.userId);
            setUsernameInput(profile.userId);
          }
