/**
 * GEO CLOCK AI - BACKEND (With OT Approval System)
 * 
 * LOGS STRUCTURE: A: Staff_ID, ..., L: Working_Hours
 * OT_REQUESTS STRUCTURE: A: Request_ID, B: Staff_ID, C: Name, D: Site_ID, E: Date, F: Reason, G: Hours, H: Status, I: Approver, J: Timestamp
 * EMPLOY_DB STRUCTURE: A: Username, B: Password/Staff_ID, C: Name, D: Site_ID, E: Role, F: Position
 */

const SHEET_EMPLOY_DB = "Employ_DB";
const SHEET_LOGS = "Logs";
const SHEET_SITE_CONFIG = "Site_Config";
const SHEET_OT_REQUESTS = "OT_Requests";
const TIMEZONE = "Asia/Bangkok"; 

function doGet(e) {
  return ContentService.createTextOutput("GeoClock AI Backend is Running.");
}

function doPost(e) {
  try {
    if (!e.postData || !e.postData.contents) return sendJSON({ success: false, message: "No data" });
    const data = JSON.parse(e.postData.contents);

    if (data.action === "LOGIN_USER") return sendJSON(handleLogin(data.username, data.password));
    if (data.action === "CLOCK_IN") return sendJSON(handleClockIn(data));
    if (data.action === "CLOCK_OUT") return sendJSON(handleClockOut(data));
    if (data.action === "REQUEST_OT") return sendJSON(handleRequestOT(data));
    if (data.action === "UPDATE_OT_STATUS") return sendJSON(handleUpdateOTStatus(data));

    return sendJSON({ success: false, message: "Invalid Action" });
  } catch (error) {
    return sendJSON({ success: false, message: error.toString() });
  }
}

function getOTRequests(staffId, role, siteId) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_OT_REQUESTS);
    sheet.appendRow(["Request_ID", "Staff_ID", "Name", "Site_ID", "Date", "Reason", "Hours", "Status", "Approver", "Timestamp"]);
  }
  const data = sheet.getDataRange().getValues();
  data.shift(); // Remove header

  return data
    .filter(row => {
      if (role === 'Supervisor') {
        return String(row[3]) === String(siteId) || row[7] === "Pending";
      }
      return String(row[1]) === String(staffId);
    })
    .map(row => ({
      id: row[0],
      staffId: row[1],
      name: row[2],
      siteId: row[3],
      date: row[4] instanceof Date ? Utilities.formatDate(row[4], TIMEZONE, "yyyy-MM-dd") : row[4],
      reason: row[5],
      hours: row[6],
      status: row[7],
      approverName: row[8],
      timestamp: row[9]
    }))
    .reverse();
}

function handleLogin(username, password) {
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]).trim() === String(username).trim() && String(row[1]).trim() === String(password).trim());

  if (!userRow) return { success: false, message: "Username หรือ Password ไม่ถูกต้อง" };

  const staffId = userRow[1];
  const userObj = { 
    username: userRow[0], 
    password: userRow[1], 
    name: userRow[2], 
    siteId: userRow[3], 
    role: userRow[4], 
    position: userRow[5] 
  };

  return {
    success: true,
    user: userObj,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userObj.role, userObj.siteId)
  };
}

function handleRequestOT(data) {
  const { staffId, name, siteId, date, reason, hours } = data;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  const requestId = "OT-" + Utilities.formatDate(new Date(), TIMEZONE, "yyyyMMdd-HHmmss") + "-" + staffId;

  sheet.appendRow([requestId, staffId, name, siteId, date, reason, hours, "Pending", "", new Date()]);

  return { 
    success: true, 
    message: "ส่งคำขอ OT เรียบร้อยแล้ว รอการอนุมัติ",
    otRequests: getOTRequests(staffId, 'Fixed', siteId)
  };
}

function handleUpdateOTStatus(data) {
  const { requestId, status, approverName, staffId, role, siteId } = data;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  const rows = sheet.getDataRange().getValues();

  for (let i = 1; i < rows.length; i++) {
    if (String(rows[i][0]) === String(requestId)) {
      sheet.getRange(i + 1, 8).setValue(status);
      sheet.getRange(i + 1, 9).setValue(approverName);
      break;
    }
  }

  return { 
    success: true, 
    message: `ทำรายการ ${status} สำเร็จ`,
    otRequests: getOTRequests(staffId, role, siteId)
  };
}

function getUserLogs(staffId) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  data.shift(); 
  return data
    .filter(row => String(row[0]) === String(staffId))
    .slice(-20)
    .map(row => ({
      staffId: row[0],
      name: row[1],
      dateIn: row[2] instanceof Date ? Utilities.formatDate(row[2], TIMEZONE, "yyyy-MM-dd") : row[2],
      timeIn: row[3],
      dateOut: row[6],
      timeOut: row[7],
      workingHours: row[11] || 0
    }));
}

function handleClockIn(data) {
  const { username, latitude, longitude } = data;
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]) === String(username));
  if (!userRow) return { success: false, message: "ไม่พบข้อมูลพนักงาน" };
  const staffId = String(userRow[1]); 
  const userRole = userRow[4];
  const siteId = userRow[3];

  const logsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  const now = new Date();
  const dateStr = Utilities.formatDate(now, TIMEZONE, "yyyy-MM-dd");
  const timeStr = Utilities.formatDate(now, TIMEZONE, "HH:mm:ss");
  logsSheet.appendRow([staffId, userRow[2], dateStr, timeStr, latitude, longitude, "", "", "", "", siteId, ""]);

  return { 
    success: true, 
    message: `บันทึกเข้างานสำเร็จ: ${timeStr}`,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userRole, siteId)
  };
}

function handleClockOut(data) {
  const { username, latitude, longitude } = data;
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]) === String(username));
  const staffId = String(userRow[1]);
  const userRole = userRow[4];
  const siteId = userRow[3];

  const logsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  const logs = logsSheet.getDataRange().getValues();
  let rowIndex = -1;
  for (let i = logs.length - 1; i >= 1; i--) {
    if (String(logs[i][0]) === staffId && String(logs[i][7]) === "") {
      rowIndex = i + 1;
      break;
    }
  }
  if (rowIndex === -1) return { success: false, message: "ไม่พบรายการเข้างานที่ยังไม่ปิดกะ" };

  const now = new Date();
  const dateOutStr = Utilities.formatDate(now, TIMEZONE, "yyyy-MM-dd");
  const timeOutStr = Utilities.formatDate(now, TIMEZONE, "HH:mm:ss");

  logsSheet.getRange(rowIndex, 7).setValue(dateOutStr);
  logsSheet.getRange(rowIndex, 8).setValue(timeOutStr);
  logsSheet.getRange(rowIndex, 12).setValue("8.00");

  return { 
    success: true, 
    message: `บันทึกออกงานสำเร็จ`,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userRole, siteId)
  };
}

function getSheetData(name) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(name);
  return sheet ? sheet.getDataRange().getValues().slice(1) : [];
}

function sendJSON(content) {
  return ContentService.createTextOutput(JSON.stringify(content)).setMimeType(ContentService.MimeType.JSON);
}

import * as React from 'react';
import { useState, useEffect } from 'react';
import { User, LogType, GeoLocationData, OTRequest, OTStatus } from './types';
import { loginUser, sendClockAction, requestOT, updateOTStatus } from './services/sheetService';
import { getDailyInsight } from './services/geminiService';
import { Button } from './components/Button';
import { AttendanceStats } from './components/AttendanceStats';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [logs, setLogs] = useState<any[]>([]);
  const [otRequests, setOtRequests] = useState<OTRequest[]>([]);

  const [usernameInput, setUsernameInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isOTModalOpen, setIsOTModalOpen] = useState(false);

  // OT Form State
  const [otDate, setOtDate] = useState(new Date().toISOString().split('T')[0]);
  const [otHours, setOtHours] = useState(2);
  const [otReason, setOtReason] = useState("");

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      const result = await loginUser(usernameInput, passwordInput);
      if (result.success && result.user) {
        setUser(result.user);
        setLogs(result.logs || []);
        setOtRequests(result.otRequests || []);
      } else {
        setError(result.message || "Login failed");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleClockIn = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_IN, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setSuccess(result.message || "Clocked In");
          const insight = await getDailyInsight(user.name, 'in', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "Clock in failed");
        }
        setIsLoading(false);
      }, (err) => {
        setError("Please enable location services.");
        setIsLoading(false);
      });
    } catch (err) {
      setError("Operation failed.");
      setIsLoading(false);
    }
  };

  const handleClockOut = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_OUT, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setSuccess(result.message || "Clocked Out");
          const insight = await getDailyInsight(user.name, 'out', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "Clock out failed");
        }
        setIsLoading(false);
      }, (err) => {
        setError("Please enable location services.");
        setIsLoading(false);
      });
    } catch (err) {
      setError("Operation failed.");
      setIsLoading(false);
    }
  };

  const handleOTRequestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await requestOT({
        staffId: user.password!,
        name: user.name,
        siteId: user.siteId,
        date: otDate,
        reason: otReason,
        hours: otHours
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setIsOTModalOpen(false);
        setSuccess(result.message || "OT Requested");
        setOtReason("");
      } else {
        setError(result.message || "Failed to request OT");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleApproveReject = async (requestId: string, status: OTStatus) => {
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await updateOTStatus({
        requestId,
        status,
        approverName: user.name,
        staffId: user.password!,
        role: user.role,
        siteId: user.siteId
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setSuccess(`OT ${status} successfully`);
      } else {
        setError(result.message || "Update failed");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 px-4">
         <div className="w-full max-w-sm bg-white p-8 rounded-3xl shadow-xl">
            <h1 className="text-3xl font-bold text-center text-slate-800 mb-2">SMC Property</h1>
            <p className="text-slate-500 text-center mb-8">Attendance & OT System</p>
            <form onSubmit={handleLogin} className="space-y-4">
              <input type="text" value={usernameInput} onChange={(e) => setUsernameInput(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-slate-50 border" placeholder="Username" />
              <input type="password" value={passwordInput} onChange={(e) => setPasswordInput(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-slate-50 border" placeholder="Staff ID (Password)" />
              {error && <div className="text-red-500 text-xs font-medium">{error}</div>}
              <Button type="submit" variant="primary" fullWidth isLoading={isLoading}>Log In</Button>
            </form>
         </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white shadow-sm p-4 sticky top-0 z-10 flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-blue-600 flex items-center justify-center text-white font-bold">{user.name.charAt(0)}</div>
             <div>
               <h2 className="font-bold text-slate-800 text-sm">{user.name}</h2>
               <p className="text-[10px] text-slate-400 uppercase">{user.position} • {user.role} • {user.siteId}</p>
             </div>
          </div>
          <button onClick={() => setUser(null)} className="text-slate-400 hover:text-red-500">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"></path>
            </svg>
          </button>
      </header>

      <main className="max-w-xl mx-auto p-4 space-y-6">
        {aiInsight && (
          <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-4 rounded-2xl shadow-lg text-white">
            <p className="text-sm font-medium italic">" {aiInsight} "</p>
          </div>
        )}

        <section className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <div className="grid grid-cols-2 gap-4">
              <Button onClick={handleClockIn} variant="primary" className="h-24 flex-col text-sm" isLoading={isLoading}><span className="text-2xl font-bold">Clock In</span></Button>
              <Button onClick={handleClockOut} variant="danger" className="h-24 flex-col text-sm" isLoading={isLoading}><span className="text-2xl font-bold">Clock Out</span></Button>
          </div>
        </section>

        <section className="space-y-3">
          <div className="flex justify-between items-center px-1">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Overtime Requests</h3>
            <button onClick={() => setIsOTModalOpen(true)} className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full">+ Request OT</button>
          </div>

          <div className="space-y-3">
            {otRequests.length === 0 ? (
              <div className="bg-white p-8 rounded-2xl text-center text-slate-400 text-sm border border-dashed">No OT requests found</div>
            ) : (
              otRequests.map(req => (
                <div key={req.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex justify-between items-center">
                  <div>
                    <div className="text-sm font-bold text-slate-700">{req.date} ({req.hours} hrs)</div>
                    <div className="text-xs text-slate-500 line-clamp-1">{req.reason}</div>
                    {user.role === 'Supervisor' && <div className="text-[10px] text-blue-500 font-bold mt-1">From: {req.name}</div>}
