  const data = sheet.getDataRange().getValues();
  data.shift(); // Remove header

  return data
    .filter(row => {
      // หัวหน้างานเห็นคำขอทั้งหมดในไซต์ หรือที่ยัง Pending
      if (role === 'Supervisor') {
        return String(row[3]) === String(siteId) || row[7] === "Pending";
      }
      // พนักงานเห็นเฉพาะของตัวเอง
      return String(row[1]) === String(staffId);
    })
    .map(row => ({
      id: row[0],
      staffId: row[1],
      name: row[2],
      siteId: row[3],
      date: row[4] instanceof Date ? Utilities.formatDate(row[4], TIMEZONE, "yyyy-MM-dd") : row[4],
      reason: row[5],
      hours: row[6],
      status: row[7],
      approverName: row[8],
      timestamp: row[9]
    }))
    .reverse();
}

function handleLogin(username, password) {
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]).trim() === String(username).trim() && String(row[1]).trim() === String(password).trim());

  if (!userRow) return { success: false, message: "Username หรือ Password ไม่ถูกต้อง" };

  const staffId = userRow[1];
  const userObj = { 
    username: userRow[0], 
    password: userRow[1], 
    name: userRow[2], 
    siteId: userRow[3], 
    role: userRow[4], 
    position: userRow[5] 
  };

  return {
    success: true,
    user: userObj,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userObj.role, userObj.siteId)
  };
}

function handleRequestOT(data) {
  const { staffId, name, siteId, date, reason, hours, role } = data;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  const requestId = "OT-" + Utilities.formatDate(new Date(), TIMEZONE, "yyyyMMdd-HHmmss") + "-" + staffId;

  sheet.appendRow([requestId, staffId, name, siteId, date, reason, hours, "Pending", "", new Date()]);

  return { 
    success: true, 
    message: "ส่งคำขอ OT เรียบร้อยแล้ว",
    otRequests: getOTRequests(staffId, role, siteId)
  };
}

function handleUpdateOTStatus(data) {
  const { requestId, status, approverName, staffId, role, siteId } = data;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  const rows = sheet.getDataRange().getValues();

  for (let i = 1; i < rows.length; i++) {
    if (String(rows[i][0]) === String(requestId)) {
      sheet.getRange(i + 1, 8).setValue(status);
      sheet.getRange(i + 1, 9).setValue(approverName);
      break;
    }
  }

  return { 
    success: true, 
    message: `ดำเนินการ ${status} สำเร็จ`,
    otRequests: getOTRequests(staffId, role, siteId)
  };
}

function getUserLogs(staffId) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  data.shift(); 
  return data
    .filter(row => String(row[0]) === String(staffId))
    .slice(-20)
    .map(row => ({
      staffId: row[0],
      name: row[1],
      dateIn: row[2] instanceof Date ? Utilities.formatDate(row[2], TIMEZONE, "yyyy-MM-dd") : row[2],
      timeIn: row[3],
      dateOut: row[6],
      timeOut: row[7],
      workingHours: row[11] || 0
    }));
}

function handleClockIn(data) {
  const { username, latitude, longitude } = data;
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]) === String(username));
  if (!userRow) return { success: false, message: "ไม่พบข้อมูลพนักงาน" };
  const staffId = String(userRow[1]); 
  const userRole = userRow[4];
  const siteId = userRow[3];

  const logsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  const now = new Date();
  const dateStr = Utilities.formatDate(now, TIMEZONE, "yyyy-MM-dd");
  const timeStr = Utilities.formatDate(now, TIMEZONE, "HH:mm:ss");
  logsSheet.appendRow([staffId, userRow[2], dateStr, timeStr, latitude, longitude, "", "", "", "", siteId, ""]);

  return { 
    success: true, 
    message: `บันทึกเข้างานสำเร็จ: ${timeStr}`,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userRole, siteId)
  };
}

function handleClockOut(data) {
  const { username, latitude, longitude } = data;
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]) === String(username));
  const staffId = String(userRow[1]);
  const userRole = userRow[4];
  const siteId = userRow[3];

  const logsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  const logs = logsSheet.getDataRange().getValues();
  let rowIndex = -1;
  for (let i = logs.length - 1; i >= 1; i--) {
    if (String(logs[i][0]) === staffId && String(logs[i][7]) === "") {
      rowIndex = i + 1;
      break;
    }
  }
  if (rowIndex === -1) return { success: false, message: "ไม่พบรายการเข้างานที่ยังไม่ปิดกะ" };

  const now = new Date();
  const dateOutStr = Utilities.formatDate(now, TIMEZONE, "yyyy-MM-dd");
  const timeOutStr = Utilities.formatDate(now, TIMEZONE, "HH:mm:ss");

  logsSheet.getRange(rowIndex, 7).setValue(dateOutStr);
  logsSheet.getRange(rowIndex, 8).setValue(timeOutStr);
  logsSheet.getRange(rowIndex, 12).setValue("8.00");

  return { 
    success: true, 
    message: `บันทึกออกงานสำเร็จ`,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userRole, siteId)
  };
}

function getSheetData(name) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(name);
  return sheet ? sheet.getDataRange().getValues().slice(1) : [];
}

function sendJSON(content) {
  return ContentService.createTextOutput(JSON.stringify(content)).setMimeType(ContentService.MimeType.JSON);
}

import { GeoLocationData, LogType, ApiResponse, OTStatus } from '../types';

const SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbzyzpngfaZlUmoAFzkCEmyayObIkxQJReT-ftdB17R4rdBknKDrmoh2GJE6os1hkBxqGQ/exec';

export const loginUser = async (username: string, password: string): Promise<ApiResponse> => {
  try {
    const response = await fetch(SCRIPT_URL, {
      method: 'POST',
      mode: 'cors',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify({ action: 'LOGIN_USER', username, password })
    });
    const text = await response.text();
    return JSON.parse(text);
  } catch (error) {
    return { success: false, message: "Connection failed." };
  }
};

export const sendClockAction = async (username: string, type: LogType, location: GeoLocationData): Promise<ApiResponse> => {
  try {
    const response = await fetch(SCRIPT_URL, {
      method: 'POST',
      mode: 'cors',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify({
        action: type,
        username,
        latitude: location.latitude,
        longitude: location.longitude,
        accuracy: location.accuracy
      })
    });
    const text = await response.text();
    return JSON.parse(text);
  } catch (error) {
    return { success: false, message: "Network error." };
  }
};

export const requestOT = async (params: { staffId: string, name: string, siteId: string, date: string, reason: string, hours: number, role: string }): Promise<ApiResponse> => {
  try {
    const response = await fetch(SCRIPT_URL, {
      method: 'POST',
      mode: 'cors',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify({ action: 'REQUEST_OT', ...params })
    });
    const text = await response.text();
    return JSON.parse(text);
  } catch (error) {
    return { success: false, message: "Failed to request OT." };
  }
};

export const updateOTStatus = async (params: { requestId: string, status: OTStatus, approverName: string, staffId: string, role: string, siteId: string }): Promise<ApiResponse> => {
  try {
    const response = await fetch(SCRIPT_URL, {
      method: 'POST',
      mode: 'cors',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify({ action: 'UPDATE_OT_STATUS', ...params })
    });
    const text = await response.text();
    return JSON.parse(text);
  } catch (error) {
    return { success: false, message: "Failed to update OT status." };
  }
};

import * as React from 'react';
import { useState, useEffect } from 'react';
import { User, LogType, GeoLocationData, OTRequest, OTStatus } from './types';
import { loginUser, sendClockAction, requestOT, updateOTStatus } from './services/sheetService';
import { getDailyInsight } from './services/geminiService';
import { Button } from './components/Button';
import { AttendanceStats } from './components/AttendanceStats';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [logs, setLogs] = useState<any[]>([]);
  const [otRequests, setOtRequests] = useState<OTRequest[]>([]);

  const [usernameInput, setUsernameInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  const [isOTModalOpen, setIsOTModalOpen] = useState(false);

  // OT Form State
  const [otDate, setOtDate] = useState(new Date().toISOString().split('T')[0]);
  const [otHours, setOtHours] = useState(2);
  const [otReason, setOtReason] = useState("");

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      const result = await loginUser(usernameInput, passwordInput);
      if (result.success && result.user) {
        setUser(result.user);
        setLogs(result.logs || []);
        setOtRequests(result.otRequests || []);
      } else {
        setError(result.message || "Login failed");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleClockIn = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_IN, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setOtRequests(result.otRequests || []);
          setSuccess(result.message || "Clocked In");
          const insight = await getDailyInsight(user.name, 'in', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "Clock in failed");
        }
        setIsLoading(false);
      }, (err) => {
        setError("Please enable location services.");
        setIsLoading(false);
      });
    } catch (err) {
      setError("Operation failed.");
      setIsLoading(false);
    }
  };

  const handleClockOut = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_OUT, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setOtRequests(result.otRequests || []);
          setSuccess(result.message || "Clocked Out");
          const insight = await getDailyInsight(user.name, 'out', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "Clock out failed");
        }
        setIsLoading(false);
      }, (err) => {
        setError("Please enable location services.");
        setIsLoading(false);
      });
    } catch (err) {
      setError("Operation failed.");
      setIsLoading(false);
    }
  };

  const handleOTRequestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await requestOT({
        staffId: user.password!,
        name: user.name,
        siteId: user.siteId,
        date: otDate,
        reason: otReason,
        hours: otHours,
        role: user.role
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setIsOTModalOpen(false);
        setSuccess(result.message || "OT Requested");
        setOtReason("");
      } else {
        setError(result.message || "Failed to request OT");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleApproveReject = async (requestId: string, status: OTStatus) => {
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await updateOTStatus({
        requestId,
        status,
        approverName: user.name,
        staffId: user.password!,
        role: user.role,
        siteId: user.siteId
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setSuccess(`OT ${status} successfully`);
      } else {
        setError(result.message || "Update failed");
      }
