/**
 * GEO CLOCK AI - BACKEND (With OT Approval System & Geofencing)
 */

const SHEET_EMPLOY_DB = "Employ_DB";
const SHEET_LOGS = "Logs";
const SHEET_SITE_CONFIG = "Site_Config";
const SHEET_OT_REQUESTS = "OT_Requests";
const TIMEZONE = "Asia/Bangkok"; 

function doGet(e) {
  return ContentService.createTextOutput("GeoClock AI Backend is Running.");
}

function doPost(e) {
  try {
    if (!e.postData || !e.postData.contents) return sendJSON({ success: false, message: "No data" });
    const data = JSON.parse(e.postData.contents);

    if (data.action === "LOGIN_USER") return sendJSON(handleLogin(data.username, data.password));
    if (data.action === "CLOCK_IN") return sendJSON(handleClockIn(data));
    if (data.action === "CLOCK_OUT") return sendJSON(handleClockOut(data));
    if (data.action === "REQUEST_OT") return sendJSON(handleRequestOT(data));
    if (data.action === "UPDATE_OT_STATUS") return sendJSON(handleUpdateOTStatus(data));

    return sendJSON({ success: false, message: "Invalid Action" });
  } catch (error) {
    return sendJSON({ success: false, message: error.toString() });
  }
}

function calculateDistance(lat1, lon1, lat2, lon2) {
  const R = 6371000; 
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * 
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

function getSiteConfig(siteId) {
  const data = getSheetData(SHEET_SITE_CONFIG);
  const site = data.find(row => String(row[0]) === String(siteId));
  if (!site) return null;
  return {
    lat: parseFloat(site[2]),
    lng: parseFloat(site[3]),
    radius: parseFloat(site[4]) || 200 
  };
}

function getOTRequests(staffId, role, siteId) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_OT_REQUESTS);
    sheet.appendRow(["Timestamp", "Request_ID", "Staff_ID", "Name", "Site_ID", "Reason", "OT_Start", "OT_End", "Status", "Approver"]);
  }
  const data = sheet.getDataRange().getValues();
  data.shift(); 

  return data
    .filter(row => {
      if (role === 'Supervisor') {
        return String(row[4]) === String(siteId) || row[8] === "Pending";
      }
      return String(row[2]) === String(staffId);
    })
    .map(row => ({
      timestamp: row[0] instanceof Date ? Utilities.formatDate(row[0], TIMEZONE, "yyyy-MM-dd HH:mm:ss") : row[0],
      id: row[1],
      staffId: row[2],
      name: row[3],
      siteId: row[4],
      reason: row[5],
      startTime: row[6] instanceof Date ? Utilities.formatDate(row[6], TIMEZONE, "yyyy-MM-dd HH:mm") : row[6],
      endTime: row[7] instanceof Date ? Utilities.formatDate(row[7], TIMEZONE, "yyyy-MM-dd HH:mm") : row[7],
      status: row[8],
      approverName: row[9]
    }))
    .reverse();
}

function handleLogin(username, password) {
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]).trim() === String(username).trim() && String(row[1]).trim() === String(password).trim());

  if (!userRow) return { success: false, message: "Username หรือ Password ไม่ถูกต้อง" };

  const staffId = userRow[1];
  const userObj = { 
    username: userRow[0], 
    password: userRow[1], 
    name: userRow[2], 
    siteId: userRow[3], 
    role: userRow[4], 
    position: userRow[5] 
  };

  return {
    success: true,
    user: userObj,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userObj.role, userObj.siteId)
  };
}

function handleRequestOT(data) {
  const { staffId, name, siteId, startTime, endTime, reason, role } = data;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  const requestId = "OT-" + Utilities.formatDate(new Date(), TIMEZONE, "yyyyMMdd-HHmmss") + "-" + staffId;

  sheet.appendRow([new Date(), requestId, staffId, name, siteId, reason, startTime, endTime, "Pending", ""]);

  return { 
    success: true, 
    message: "ส่งคำขอ OT เรียบร้อยแล้ว",
    otRequests: getOTRequests(staffId, role, siteId)
  };
}

function handleUpdateOTStatus(data) {
  const { requestId, status, approverName, staffId, role, siteId } = data;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_OT_REQUESTS);
  const rows = sheet.getDataRange().getValues();

  for (let i = 1; i < rows.length; i++) {
    if (String(rows[i][1]) === String(requestId)) {
      sheet.getRange(i + 1, 9).setValue(status);
      sheet.getRange(i + 1, 10).setValue(approverName);
      break;
    }
  }

  return { 
    success: true, 
    message: `ดำเนินการ ${status} สำเร็จ`,
    otRequests: getOTRequests(staffId, role, siteId)
  };
}

function getUserLogs(staffId) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  data.shift(); 
  return data
    .filter(row => String(row[0]) === String(staffId))
    .slice(-20)
    .map(row => ({
      staffId: row[0],
      name: row[1],
      dateIn: row[2] instanceof Date ? Utilities.formatDate(row[2], TIMEZONE, "yyyy-MM-dd") : row[2],
      timeIn: row[3] instanceof Date ? Utilities.formatDate(row[3], TIMEZONE, "HH:mm:ss") : row[3],
      dateOut: row[6] instanceof Date ? Utilities.formatDate(row[6], TIMEZONE, "yyyy-MM-dd") : row[6],
      timeOut: row[7] instanceof Date ? Utilities.formatDate(row[7], TIMEZONE, "HH:mm:ss") : row[7],
      workingHours: row[11] || "0 นาที"
    }));
}

function validateLocation(role, siteId, userLat, userLng) {
  if (role !== 'Fixed') return { allowed: true };

  const config = getSiteConfig(siteId);
  if (!config) return { allowed: false, message: "ไม่พบการตั้งค่าพิกัดสำหรับไซต์งานนี้" };

  const distance = calculateDistance(userLat, userLng, config.lat, config.lng);
  if (distance > config.radius) {
    return { 
      allowed: false, 
      message: `อยู่นอกพื้นที่ปฏิบัติงาน (${distance.toFixed(0)} ม.) รัศมีที่อนุญาตคือ ${config.radius} ม.` 
    };
  }

  return { allowed: true };
}

function handleClockIn(data) {
  const { username, latitude, longitude } = data;
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]) === String(username));
  if (!userRow) return { success: false, message: "ไม่พบข้อมูลพนักงาน" };

  const staffId = String(userRow[1]); 
  const siteId = userRow[3];
  const userRole = userRow[4]; // แก้ไขจาก const userRole = userRole = userRow[4];

  const locationCheck = validateLocation(userRole, siteId, latitude, longitude);
  if (!locationCheck.allowed) return { success: false, message: locationCheck.message };

  const logsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  const now = new Date();
  const dateStr = Utilities.formatDate(now, TIMEZONE, "yyyy-MM-dd");
  const timeStr = Utilities.formatDate(now, TIMEZONE, "HH:mm:ss");
  logsSheet.appendRow([staffId, userRow[2], dateStr, timeStr, latitude, longitude, "", "", "", "", siteId, ""]);

  return { 
    success: true, 
    message: `บันทึกเข้างานสำเร็จ: ${timeStr}`,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userRole, siteId)
  };
}

function handleClockOut(data) {
  const { username, latitude, longitude } = data;
  const db = getSheetData(SHEET_EMPLOY_DB);
  const userRow = db.find(row => String(row[0]) === String(username));
  if (!userRow) return { success: false, message: "ไม่พบข้อมูลพนักงาน" };

  const staffId = String(userRow[1]);
  const siteId = userRow[3];
  const userRole = userRow[4];

  const locationCheck = validateLocation(userRole, siteId, latitude, longitude);
  if (!locationCheck.allowed) return { success: false, message: locationCheck.message };

  const logsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_LOGS);
  const logs = logsSheet.getDataRange().getValues();
  let rowIndex = -1;
  for (let i = logs.length - 1; i >= 1; i--) {
    if (String(logs[i][0]) === staffId && (logs[i][7] === "" || logs[i][7] == null)) {
      rowIndex = i + 1;
      break;
    }
  }
  if (rowIndex === -1) return { success: false, message: "ไม่พบการลงเวลาเข้างาน" };

  const now = new Date();
  const dateOutStr = Utilities.formatDate(now, TIMEZONE, "yyyy-MM-dd");
  const timeOutStr = Utilities.formatDate(now, TIMEZONE, "HH:mm:ss");

  let workingHoursResult = "0 นาที";
  try {
    const rowData = logs[rowIndex-1];
    const dateInVal = rowData[2];
    const timeInVal = rowData[3];

    const dateInStr = dateInVal instanceof Date ? Utilities.formatDate(dateInVal, TIMEZONE, "yyyy-MM-dd") : String(dateInVal);
    const timeInStr = timeInVal instanceof Date ? Utilities.formatDate(timeInVal, TIMEZONE, "HH:mm:ss") : String(timeInVal);

    const startTime = new Date(dateInStr.split('T')[0] + "T" + timeInStr);
    const diffMs = now.getTime() - startTime.getTime();

    if (!isNaN(diffMs)) {
      const totalMinutes = Math.round(diffMs / (1000 * 60));
      const h = Math.floor(totalMinutes / 60);
      const m = totalMinutes % 60;
      workingHoursResult = h > 0 ? h + " ชม. " + m + " นาที" : m + " นาที";
    }
  } catch (e) {
    workingHoursResult = "0 นาที";
  }

  logsSheet.getRange(rowIndex, 7).setValue(dateOutStr);
  logsSheet.getRange(rowIndex, 8).setValue(timeOutStr);
  logsSheet.getRange(rowIndex, 9).setValue(latitude);
  logsSheet.getRange(rowIndex, 10).setValue(longitude);
  logsSheet.getRange(rowIndex, 12).setValue(workingHoursResult);

  return { 
    success: true, 
    message: `บันทึกออกงานสำเร็จ (${workingHoursResult})`,
    logs: getUserLogs(staffId),
    otRequests: getOTRequests(staffId, userRole, siteId)
  };
}

function getSheetData(name) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(name);
  return sheet ? sheet.getDataRange().getValues().slice(1) : [];
}

function sendJSON(content) {
  return ContentService.createTextOutput(JSON.stringify(content)).setMimeType(ContentService.MimeType.JSON);
}

import * as React from 'react';
import { useState, useEffect } from 'react';
import { User, LogType, GeoLocationData, OTRequest, OTStatus } from './types';
import { loginUser, sendClockAction, requestOT, updateOTStatus } from './services/sheetService';
import { getDailyInsight } from './services/geminiService';
import { initLiff, getLineProfile, LineProfile } from './services/lineService';
import { Button } from './components/Button';
import { AttendanceStats } from './components/AttendanceStats';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [lineProfile, setLineProfile] = useState<LineProfile | null>(null);
  const [logs, setLogs] = useState<any[]>([]);
  const [otRequests, setOtRequests] = useState<OTRequest[]>([]);

  const [usernameInput, setUsernameInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  const [isOTModalOpen, setIsOTModalOpen] = useState(false);

  // Set default start time to today at 18:00
  const defaultStart = new Date();
  defaultStart.setHours(18, 0, 0, 0);
  const defaultEnd = new Date();
  defaultEnd.setHours(20, 0, 0, 0);

  const [otStartTime, setOtStartTime] = useState(defaultStart.toISOString().slice(0, 16));
  const [otEndTime, setOtEndTime] = useState(defaultEnd.toISOString().slice(0, 16));
  const [otReason, setOtReason] = useState("");

  // Initialize LIFF and check if already logged in
  useEffect(() => {
    const startLiff = async () => {
      const ok = await initLiff();
      if (ok) {
        try {
          // @ts-ignore
          if (window.liff.isLoggedIn()) {
            const profile = await getLineProfile();
            if (profile) {
              setLineProfile(profile);
              setUsernameInput(profile.userId);
            }
          }
        } catch (e) {
          console.log("LIFF check failed", e);
        }
      }
    };
    startLiff();
  }, []);

  const handleLineConnect = async () => {
    setIsLoading(true);
    const profile = await getLineProfile();
    if (profile) {
      setLineProfile(profile);
      setUsernameInput(profile.userId);
      setSuccess("เชื่อมต่อ LINE สำเร็จ!");
    }
    setIsLoading(false);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      const result = await loginUser(usernameInput, passwordInput);
      if (result.success && result.user) {
        setUser(result.user);
        setLogs(result.logs || []);
        setOtRequests(result.otRequests || []);
      } else {
        setError(result.message || "การเข้าสู่ระบบล้มเหลว ตรวจสอบรหัสพนักงานของคุณ");
      }
    } catch (err) {
      setError("เกิดข้อผิดพลาดในการเชื่อมต่อ กรุณาลองใหม่");
    } finally {
      setIsLoading(false);
    }
  };

  const handleClockIn = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_IN, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setOtRequests(result.otRequests || []);
          setSuccess(result.message || "บันทึกเข้างานสำเร็จ");
          const insight = await getDailyInsight(user.name, 'in', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "บันทึกเข้างานไม่สำเร็จ");
        }
        setIsLoading(false);
      }, (err) => {
        setError("กรุณาเปิดการเข้าถึงพิกัด (Location Services)");
        setIsLoading(false);
      });
    } catch (err) {
      setError("การดำเนินการล้มเหลว");
      setIsLoading(false);
    }
  };

  const handleClockOut = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_OUT, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setOtRequests(result.otRequests || []);
          setSuccess(result.message || "บันทึกออกงานสำเร็จ");
          const insight = await getDailyInsight(user.name, 'out', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "บันทึกออกงานไม่สำเร็จ");
        }
        setIsLoading(false);
      }, (err) => {
        setError("กรุณาเปิดการเข้าถึงพิกัด (Location Services)");
        setIsLoading(false);
      });
    } catch (err) {
      setError("การดำเนินการล้มเหลว");
      setIsLoading(false);
    }
  };

  const handleOTRequestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await requestOT({
        staffId: user.password!,
        name: user.name,
        siteId: user.siteId,
        startTime: otStartTime.replace('T', ' '),
        endTime: otEndTime.replace('T', ' '),
        reason: otReason,
        role: user.role
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setIsOTModalOpen(false);
        setSuccess(result.message || "ส่งคำขอ OT เรียบร้อยแล้ว");
        setOtReason("");
      } else {
        setError(result.message || "ส่งคำขอ OT ล้มเหลว");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleApproveReject = async (requestId: string, status: OTStatus) => {
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await updateOTStatus({
        requestId,
        status,
        approverName: user.name,
        staffId: user.password!,
        role: user.role,
        siteId: user.siteId
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setSuccess(`ดำเนินการ ${status === OTStatus.APPROVED ? 'อนุมัติ' : 'ปฏิเสธ'} เรียบร้อยแล้ว`);
      } else {
        setError(result.message || "การอัปเดตล้มเหลว");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 px-4">
         <div className="w-full max-w-sm bg-white p-8 rounded-[40px] shadow-2xl border border-slate-100 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-6">
              <button 
                onClick={handleLineConnect}
                className={`p-3 rounded-full transition-all ${lineProfile ? 'bg-green-100 text-green-600 shadow-inner' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 shadow-sm border border-slate-100'}`}
                title="Connect LINE"
              >
                {lineProfile?.pictureUrl ? (
                  <img src={lineProfile.pictureUrl} className="w-8 h-8 rounded-full border-2 border-green-400" alt="Profile" />
                ) : (
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                )}
              </button>
            </div>

            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto mb-6 flex items-center justify-center shadow-2xl shadow-blue-200 transform rotate-3 hover:rotate-0 transition-transform">
              <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"></path></svg>
            </div>

            <h1 className="text-3xl font-black text-center text-slate-800 mb-1">GeoClock</h1>
            <p className="text-slate-400 text-center text-sm mb-8 font-medium italic">SMC Attendance System</p>

            <form onSubmit={handleLogin} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">User ID</label>
                <input 
                  type="text" 
                  value={usernameInput} 
                  onChange={(e) => setUsernameInput(e.target.value)} 
                  readOnly={!!lineProfile}
                  className={`w-full px-5 py-4 rounded-2xl border outline-none transition-all font-semibold ${lineProfile ? 'bg-slate-100 border-slate-200 text-slate-500 cursor-not-allowed' : 'bg-slate-50 border-slate-200 focus:ring-4 focus:ring-blue-100 focus:border-blue-400'}`} 
                  placeholder={lineProfile ? usernameInput : "กรุณากดไอคอนเพื่อเชื่อมต่อ LINE"} 
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Staff ID</label>
                <input 
                  type="text" 
                  value={passwordInput} 
                  onChange={(e) => setPasswordInput(e.target.value)} 
                  className="w-full px-5 py-4 rounded-2xl bg-slate-50 border border-slate-200 focus:ring-4 focus:ring-blue-100 focus:border-blue-400 outline-none transition-all font-semibold" 
                  placeholder="กรอกรหัสพนักงาน" 
                />
              </div>
              {error && <div className="text-red-500 text-[11px] font-bold bg-red-50 p-3 rounded-xl border border-red-100 animate-pulse">{error}</div>}
              <Button type="submit" variant="primary" fullWidth className="py-5 text-lg shadow-blue-300" isLoading={isLoading} disabled={!usernameInput}>Log In</Button>
            </form>
            <p className="mt-6 text-center text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Management By SMC Property Soft</p>
         </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white/80 backdrop-blur-md shadow-sm p-4 sticky top-0 z-10 flex justify-between items-center border-b border-slate-100">
          <div className="flex items-center gap-3">
             <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-blue-600 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-200 overflow-hidden">
               {lineProfile?.pictureUrl ? (
                 <img src={lineProfile.pictureUrl} className="w-full h-full object-cover" alt="LINE" />
               ) : (
                 <span className="text-white font-bold text-xl">{user.name.charAt(0)}</span>
               )}
             </div>
             <div>
               <h2 className="font-black text-slate-800 text-sm leading-tight">{user.name}</h2>
               <p className="text-[10px] text-slate-400 uppercase tracking-widest font-black opacity-70">{user.position} • {user.siteId}</p>
             </div>
          </div>
          <button onClick={() => setUser(null)} className="text-slate-300 hover:text-red-500 p-2.5 bg-slate-50 rounded-2xl transition-all hover:bg-red-50">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path>
            </svg>
          </button>
      </header>

      <main className="max-w-xl mx-auto p-4 space-y-6">
        {aiInsight && (
          <div className="bg-gradient-to-br from-blue-600 via-indigo-600 to-purple-600 p-5 rounded-[32px] shadow-2xl shadow-blue-200 text-white animate-fade-in relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 w-24 h-24 bg-white/10 rounded-full blur-2xl group-hover:scale-150 transition-transform"></div>
            <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 bg-white/20 rounded-lg">
                <svg className="w-4 h-4 text-blue-100" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-11a1 1 0 10-2 0v2H7a1 1 0 100 2h2v2a1 1 0 102 0v-2h2a1 1 0 100-2h-2V7z"></path></svg>
              </div>
              <span className="text-[11px] font-black uppercase tracking-[0.2em] text-blue-100">Smart Insight</span>
            </div>
            <p className="text-lg font-bold leading-tight italic drop-shadow-md">" {aiInsight} "</p>
          </div>
        )}

        <section className="bg-white p-8 rounded-[40px] shadow-xl shadow-slate-200/50 border border-slate-50">
          <div className="grid grid-cols-2 gap-6">
              <Button onClick={handleClockIn} variant="primary" className="h-32 flex-col text-sm rounded-[32px]" isLoading={isLoading}>
                <div className="p-3 bg-white/20 rounded-2xl mb-2">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 16l-4-4m0 0l4-4m-4 4h14m-5 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                </div>
                <span className="text-xl font-black">Clock In</span>
              </Button>
              <Button onClick={handleClockOut} variant="danger" className="h-32 flex-col text-sm rounded-[32px]" isLoading={isLoading}>
                <div className="p-3 bg-white/20 rounded-2xl mb-2">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                </div>
                <span className="text-xl font-black">Clock Out</span>
              </Button>
          </div>
        </section>

        <section className="space-y-4">
          <div className="flex justify-between items-center px-2">
            <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Active Requests</h3>
            <button 
              onClick={() => setIsOTModalOpen(true)} 
              className="text-[11px] font-black text-blue-600 bg-blue-50 px-5 py-2.5 rounded-full hover:bg-blue-600 hover:text-white transition-all flex items-center gap-2 shadow-sm active:scale-95"
            >
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"></path></svg>
              REQUEST OT
            </button>
          </div>

          <div className="space-y-4">
            {otRequests.length === 0 ? (
              <div className="bg-white p-12 rounded-[40px] text-center text-slate-400 text-sm border-2 border-dashed border-slate-100">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-8 h-8 text-slate-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                </div>
                <p className="font-bold tracking-tight">ไม่พบคำขอที่อยู่ระหว่างดำเนินการ</p>
              </div>
            ) : (
              otRequests.map(req => (
                <div key={req.id} className="bg-white p-5 rounded-[32px] shadow-lg shadow-slate-100/50 border border-slate-50 flex justify-between items-start transition-all hover:translate-y-[-2px]">
                  <div className="space-y-1">
                    <div className="flex flex-col mb-1">
                       <span className="text-[10px] text-blue-600 font-black uppercase tracking-widest mb-0.5">Time Range</span>
                       <span className="text-xs font-black text-slate-800">{req.startTime} น.</span>
                       <span className="text-xs font-black text-slate-400 flex items-center gap-1">
                         <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 14l-7 7m0 0l-7-7m7 7V3" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                         {req.endTime} น.
                       </span>
                    </div>
                    <p className="text-xs text-slate-500 font-medium leading-relaxed max-w-[210px] mt-2">{req.reason}</p>
                    {user.role === 'Supervisor' && (
                       <div className="flex items-center gap-2 mt-3 p-1.5 bg-slate-50 rounded-2xl w-fit">
                         <div className="w-6 h-6 rounded-xl bg-blue-600 flex items-center justify-center text-[10px] font-black text-white shadow-sm">{req.name.charAt(0)}</div>
                         <span className="text-[10px] text-slate-600 font-black tracking-tight">{req.name}</span>
                       </div>
                    )}
                  </div>
                  <div className="flex flex-col items-end gap-4">
                    <span className={`text-[9px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest shadow-sm border-2 ${
                      req.status === 'Approved' ? 'bg-green-50 text-green-600 border-green-100' :
                      req.status === 'Rejected' ? 'bg-red-50 text-red-600 border-red-100' : 'bg-yellow-50 text-yellow-600 border-yellow-100 animate-pulse'
                    }`}>
                      {req.status === 'Approved' ? 'อนุมัติแล้ว' : req.status === 'Rejected' ? 'ปฏิเสธ' : 'รออนุมัติ'}
                    </span>
                    {user.role === 'Supervisor' && req.status === 'Pending' && (
                      <div className="flex gap-2">
                        <button 
                          onClick={() => handleApproveReject(req.id, OTStatus.APPROVED)} 
                          className="p-3 bg-green-500 text-white hover:bg-green-600 rounded-2xl transition-all shadow-lg shadow-green-100 active:scale-90"
                          title="Approve"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M5 13l4 4L19 7" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                        </button>
                        <button 
                          onClick={() => handleApproveReject(req.id, OTStatus.REJECTED)} 
                          className="p-3 bg-red-500 text-white hover:bg-red-600 rounded-2xl transition-all shadow-lg shadow-red-100 active:scale-90"
                          title="Reject"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </section>

        <section>
          <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-5 ml-2">Monthly Stats</h3>
          <AttendanceStats logs={logs} />
        </section>
      </main>

      {/* OT Request Modal */}
      {isOTModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-md animate-fade-in">
          <div className="bg-white rounded-[48px] shadow-2xl w-full max-w-sm p-10 space-y-8 animate-scale-in relative border border-slate-100">
            <button onClick={() => setIsOTModalOpen(false)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 transition-colors p-2 bg-slate-50 rounded-2xl">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
            </button>

            <div className="space-y-2">
              <h3 className="text-3xl font-black text-slate-800">New Request</h3>
              <p className="text-slate-400 font-medium text-sm">ระบุช่วงเวลาที่คุณจะทำ OT</p>
            </div>

            <form onSubmit={handleOTRequestSubmit} className="space-y-5">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">เวลาเริ่มต้น</label>
                <input 
                  type="datetime-local" 
                  value={otStartTime} 
                  onChange={(e) => setOtStartTime(e.target.value)} 
                  className="w-full px-6 py-4 rounded-[24px] bg-slate-50 border border-slate-200 outline-none focus:ring-4 focus:ring-blue-50 transition-all font-bold text-sm" 
                  required 
                />
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">เวลาสิ้นสุด</label>
                <input 
                  type="datetime-local" 
                  value={otEndTime} 
                  onChange={(e) => setOtEndTime(e.target.value)} 
                  className="w-full px-6 py-4 rounded-[24px] bg-slate-50 border border-slate-200 outline-none focus:ring-4 focus:ring-blue-50 transition-all font-bold text-sm" 
                  required 
                />
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">รายละเอียด / เหตุผล</label>
                <textarea 
                  value={otReason} 
                  onChange={(e) => setOtReason(e.target.value)} 
                  className="w-full px-6 py-5 rounded-[24px] bg-slate-50 border border-slate-200 outline-none focus:ring-4 focus:ring-blue-50 transition-all font-bold h-28 resize-none text-sm" 
                  placeholder="คุณกำลังจะทำงานอะไร?" 
                  required
                ></textarea>
              </div>
              <div className="flex gap-4 pt-2">
                <Button type="submit" variant="primary" fullWidth className="py-5 text-lg" isLoading={isLoading}>ส่งคำขอ</Button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Floating Notifications */}
      {(success || error) && (
        <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 px-8 py-5 rounded-[28px] shadow-2xl z-50 text-white font-black text-sm flex items-center gap-4 min-w-[320px] transition-all transform animate-bounce-short border-4 border-white/20 ${success ? 'bg-green-500' : 'bg-red-500'}`}>
          <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center">
            {success ? (
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M5 13l4 4L19 7" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"></path></svg>
            ) : (
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"></path></svg>
            )}
          </div>
          <span className="flex-1 uppercase tracking-tight">{success || error}</span>
          <button onClick={() => {setSuccess(null); setError(null)}} className="hover:scale-125 transition-transform p-1">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"></path></svg>
          </button>
        </div>
      )}

      <style>{`
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes scale-in { from { opacity: 0; transform: scale(0.9) translateY(20px); } to { opacity: 1; transform: scale(1) translateY(0); } }
        @keyframes bounce-short { 0%, 100% { transform: translate(-50%, 0); } 50% { transform: translate(-50%, -15px); } }
        .animate-fade-in { animation: fade-in 0.4s ease-out; }
        .animate-scale-in { animation: scale-in 0.5: cubic-bezier(0.34, 1.56, 0.64, 1); }
        .animate-bounce-short { animation: bounce-short 2s ease-in-out infinite; }
      `}</style>
    </div>
  );
};

export default App;

import * as React from 'react';
import { useState, useEffect } from 'react';
import { User, LogType, GeoLocationData, OTRequest, OTStatus } from './types';
import { loginUser, sendClockAction, requestOT, updateOTStatus } from './services/sheetService';
import { getDailyInsight } from './services/geminiService';
import { initLiff, getLineProfile, LineProfile } from './services/lineService';
import { Button } from './components/Button';
import { AttendanceStats } from './components/AttendanceStats';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [lineProfile, setLineProfile] = useState<LineProfile | null>(null);
  const [logs, setLogs] = useState<any[]>([]);
  const [otRequests, setOtRequests] = useState<OTRequest[]>([]);

  const [usernameInput, setUsernameInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  const [isOTModalOpen, setIsOTModalOpen] = useState(false);

  const defaultStart = new Date();
  defaultStart.setHours(18, 0, 0, 0);
  const defaultEnd = new Date();
  defaultEnd.setHours(20, 0, 0, 0);

  const [otStartTime, setOtStartTime] = useState(defaultStart.toISOString().slice(0, 16));
  const [otEndTime, setOtEndTime] = useState(defaultEnd.toISOString().slice(0, 16));
  const [otReason, setOtReason] = useState("");

  useEffect(() => {
    const startLiff = async () => {
      const ok = await initLiff();
      if (ok) {
        try {
          // @ts-ignore
          if (window.liff.isLoggedIn()) {
            const profile = await getLineProfile();
            if (profile) {
              setLineProfile(profile);
              setUsernameInput(profile.userId);
            }
          }
        } catch (e) {
          console.log("LIFF check failed", e);
        }
      }
    };
    startLiff();
  }, []);

  const handleLineConnect = async () => {
    setIsLoading(true);
    const profile = await getLineProfile();
    if (profile) {
      setLineProfile(profile);
      setUsernameInput(profile.userId);
      setSuccess("เชื่อมต่อ LINE สำเร็จ!");
    }
    setIsLoading(false);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      const result = await loginUser(usernameInput, passwordInput);
      if (result.success && result.user) {
        setUser(result.user);
        setLogs(result.logs || []);
        setOtRequests(result.otRequests || []);
      } else {
        setError(result.message || "การเข้าสู่ระบบล้มเหลว ตรวจสอบรหัสพนักงานของคุณ");
      }
    } catch (err) {
      setError("เกิดข้อผิดพลาดในการเชื่อมต่อ กรุณาลองใหม่");
    } finally {
      setIsLoading(false);
    }
  };

  const handleClockIn = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_IN, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setOtRequests(result.otRequests || []);
          setSuccess(result.message || "บันทึกเข้างานสำเร็จ");
          const insight = await getDailyInsight(user.name, 'in', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "บันทึกเข้างานไม่สำเร็จ");
        }
        setIsLoading(false);
      }, (err) => {
        setError("กรุณาเปิดการเข้าถึงพิกัด (Location Services)");
        setIsLoading(false);
      });
    } catch (err) {
      setError("การดำเนินการล้มเหลว");
      setIsLoading(false);
    }
  };

  const handleClockOut = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const result = await sendClockAction(user.username, LogType.CLOCK_OUT, {
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          accuracy: pos.coords.accuracy
        });
        if (result.success) {
          setLogs(result.logs || []);
          setOtRequests(result.otRequests || []);
          setSuccess(result.message || "บันทึกออกงานสำเร็จ");
          const insight = await getDailyInsight(user.name, 'out', new Date().toLocaleTimeString());
          setAiInsight(insight);
        } else {
          setError(result.message || "บันทึกออกงานไม่สำเร็จ");
        }
        setIsLoading(false);
      }, (err) => {
        setError("กรุณาเปิดการเข้าถึงพิกัด (Location Services)");
        setIsLoading(false);
      });
    } catch (err) {
      setError("การดำเนินการล้มเหลว");
      setIsLoading(false);
    }
  };

  const handleOTRequestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await requestOT({
        staffId: user.password!,
        name: user.name,
        siteId: user.siteId,
        startTime: otStartTime.replace('T', ' '),
        endTime: otEndTime.replace('T', ' '),
        reason: otReason,
        role: user.role
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setIsOTModalOpen(false);
        setSuccess(result.message || "ส่งคำขอ OT เรียบร้อยแล้ว");
        setOtReason("");
      } else {
        setError(result.message || "ส่งคำขอ OT ล้มเหลว");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleApproveReject = async (requestId: string, status: OTStatus) => {
    if (!user) return;
    setIsLoading(true);
    try {
      const result = await updateOTStatus({
        requestId,
        status,
        approverName: user.name,
        staffId: user.password!,
        role: user.role,
        siteId: user.siteId
      });
      if (result.success) {
        setOtRequests(result.otRequests || []);
        setSuccess(`ดำเนินการ ${status === OTStatus.APPROVED ? 'อนุมัติ' : 'ปฏิเสธ'} เรียบร้อยแล้ว`);
      } else {
        setError(result.message || "การอัปเดตล้มเหลว");
      }
    } catch (err) {
      setError("Network error.");
    } finally {
      setIsLoading(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-white px-6">
         <div className="w-full max-w-sm bg-white p-10 pt-16 rounded-[60px] shadow-[0_35px_60px_-15px_rgba(0,0,0,0.1)] relative border border-slate-50">

            {/* Profile Section */}
            <div className="flex flex-col items-center mb-8 relative">
              <div className="relative inline-block group cursor-pointer" onClick={handleLineConnect}>
                <div className="w-28 h-28 rounded-[36px] overflow-hidden border-4 border-white shadow-xl bg-slate-100 flex items-center justify-center">
                  {lineProfile?.pictureUrl ? (
                    <img src={lineProfile.pictureUrl} className="w-full h-full object-cover" alt="Profile" />
                  ) : (
                    <svg className="w-12 h-12 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z"/></svg>
                  )}
                </div>
                {/* Verified Icon */}
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-xl p-1.5 border-4 border-white shadow-lg">
                  <svg className="w-3.5 h-3.5 text-white" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M2.166 4.9L9.03 1.05a2 2 0 011.939 0L17.833 4.9a2 2 0 011.167 1.787V11a8.96 8.96 0 01-2.341 6.023 2 2 0 01-2.261.439l-4.031-2.02a2 2 0 00-1.794 0l-4.031 2.02a2 2 0 01-2.261-.439A8.96 8.96 0 011 11V6.687c0-.737.405-1.41 1.166-1.787zM13.707 8.707a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                  </svg>
                </div>
              </div>

              <h1 className="text-3xl font-black text-slate-800 mt-6 mb-1 tracking-tight">GeoClock</h1>
              <p className="text-slate-400 text-sm font-medium italic">SMC Attendance System</p>
            </div>

            <form onSubmit={handleLogin} className="space-y-6">
              {/* USE ID Field */}
              <div className="space-y-2">
                <div className="flex items-center gap-2 ml-1">
                  <svg className="w-3.5 h-3.5 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                  <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.15em]">USE ID</label>
                </div>
                <div className="bg-[#f1f6ff] rounded-[24px] px-6 py-5 border border-slate-100/50">
                  <input 
                    type="text" 
                    value={usernameInput} 
                    onChange={(e) => setUsernameInput(e.target.value)} 
                    readOnly={!!lineProfile}
                    className="w-full bg-transparent outline-none text-slate-500 font-bold text-sm truncate" 
                    placeholder="กรุณาเชื่อมต่อ LINE" 
                  />
                </div>
              </div>

              {/* STAFF ID Field */}
              <div className="space-y-2">
                <div className="flex items-center gap-2 ml-1">
                  <svg className="w-3.5 h-3.5 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                  <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.15em]">STAFF ID</label>
                </div>
                <div className="bg-white rounded-[24px] px-6 py-7 border-2 border-slate-50 shadow-[0_8px_30px_rgb(0,0,0,0.04)] flex items-center gap-3">
                  <span className="text-slate-300 text-2xl font-light">#</span>
                  <input 
                    type="text" 
                    value={passwordInput} 
                    onChange={(e) => setPasswordInput(e.target.value)} 
                    className="w-full bg-transparent outline-none text-slate-800 font-black text-2xl tracking-tight placeholder:text-slate-200" 
                    placeholder="2624" 
                  />
                </div>
              </div>

              {error && <div className="text-red-500 text-[11px] font-bold bg-red-50 p-3 rounded-xl border border-red-100">{error}</div>}

              {/* Login Button */}
              <Button 
                type="submit" 
                variant="primary" 
                fullWidth 
                className="py-6 rounded-[28px] text-lg font-black shadow-2xl shadow-blue-200 uppercase tracking-widest gap-3" 
                isLoading={isLoading} 
                disabled={!usernameInput}
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"></path>
                </svg>
                Login
              </Button>
            </form>

            <p className="mt-10 text-center text-[10px] text-slate-300 font-black uppercase tracking-widest">Management By SMC Property Soft</p>
         </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white/80 backdrop-blur-md shadow-sm p-4 sticky top-0 z-10 flex justify-between items-center border-b border-slate-100">
          <div className="flex items-center gap-3">
             <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-blue-600 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-200 overflow-hidden">
               {lineProfile?.pictureUrl ? (
                 <img src={lineProfile.pictureUrl} className="w-full h-full object-cover" alt="LINE" />
               ) : (
                 <span className="text-white font-bold text-xl">{user.name.charAt(0)}</span>
               )}
